at::Tensor gather_points_kernel_wrapper(int b, int c, int n, int npoints, const at::Tensor points, const at::Tensor idx) {
  auto idx_long = idx.to(at::kLong);
  auto gather_idx = idx_long.unsqueeze(1).expand({b, c, npoints});
  return points.gather(2, gather_idx).contiguous();
}

at::Tensor gather_points_grad_kernel_wrapper(int b, int c, int n, int npoints, const at::Tensor grad_out, const at::Tensor idx) {
  auto grad = at::zeros({b, c, n}, grad_out.options());
  auto idx_long = idx.to(at::kLong).unsqueeze(1).expand({b, c, npoints});
  return grad.scatter_add(2, idx_long, grad_out).contiguous();
}

